import { useEffect, useState } from 'react';

// Utilitaire pour convertir la clé VAPID
function urlBase64ToUint8Array(base64String) {
  const padding = "=".repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/\-/g, "+").replace(/_/g, "/");
  const rawData = window.atob(base64);
  return Uint8Array.from([...rawData].map((c) => c.charCodeAt(0)));
}

export const usePushNotifications = () => {
  const [isSupported, setIsSupported] = useState(false);
  const [isSubscribed, setIsSubscribed] = useState(false);
  const [subscription, setSubscription] = useState(null);
  const [vapidPublicKey, setVapidPublicKey] = useState(null);
  const [hasAskedPermission, setHasAskedPermission] = useState(false);

  // Récupérer la clé publique VAPID depuis le backend
  useEffect(() => {
    const fetchVapidKey = async () => {
      try {
        const response = await fetch(`${process.env.REACT_APP_BACKEND_URL}/api/push/vapid-public-key`);
        const data = await response.json();
        setVapidPublicKey(data.publicKey);
      } catch (error) {
        console.error('Erreur lors de la récupération de la clé VAPID:', error);
      }
    };

    fetchVapidKey();
  }, []);

  // Vérifier le support des notifications push et demander l'autorisation automatiquement
  useEffect(() => {
    const checkSupport = () => {
      const supported = "serviceWorker" in navigator && "PushManager" in window;
      setIsSupported(supported);
    };

    checkSupport();
  }, []);

  // Demande automatique d'autorisation au chargement de l'app
  useEffect(() => {
    const autoRequestPermission = async () => {
      // Vérifier si on a déjà demandé la permission dans cette session
      const sessionAsked = sessionStorage.getItem('push-permission-asked');
      if (sessionAsked) {
        setHasAskedPermission(true);
        return;
      }

      // Vérifier si les notifications sont supportées et si la clé VAPID est disponible
      if (!isSupported || !vapidPublicKey) {
        return;
      }

      // Vérifier l'état actuel de la permission
      if (Notification.permission === 'default') {
        // Attendre un peu pour que l'utilisateur soit bien sur l'app
        setTimeout(async () => {
          try {
            const reg = await navigator.serviceWorker.ready;
            const existingSubscription = await reg.pushManager.getSubscription();

            // Si pas d'abonnement existant, demander la permission
            if (!existingSubscription) {
              const permission = await Notification.requestPermission();
              setHasAskedPermission(true);
              sessionStorage.setItem('push-permission-asked', 'true');

              if (permission === 'granted') {
                // Auto-s'abonner si la permission est accordée
                await subscribeUser();
              }
            } else {
              // Déjà abonné
              setSubscription(existingSubscription);
              setIsSubscribed(true);
              setHasAskedPermission(true);
            }
          } catch (error) {
            console.error('Erreur lors de la demande automatique de permission:', error);
            setHasAskedPermission(true);
            sessionStorage.setItem('push-permission-asked', 'true');
          }
        }, 3000); // Attendre 3 secondes après le chargement
      } else {
        setHasAskedPermission(true);
        sessionStorage.setItem('push-permission-asked', 'true');
      }
    };

    autoRequestPermission();
  }, [isSupported, vapidPublicKey]);

  // S'abonner aux notifications push
  const subscribeUser = async () => {
    if (!isSupported || !vapidPublicKey) {
      console.log('Notifications push non supportées ou clé VAPID manquante');
      return false;
    }

    try {
      // Enregistrer le service worker
      const reg = await navigator.serviceWorker.register("/serviceWorker.js");

      // Demander la permission
      const permission = await Notification.requestPermission();
      if (permission !== "granted") {
        console.log("Permission refusée");
        return false;
      }

      // Vérifier si déjà abonné
      const existingSubscription = await reg.pushManager.getSubscription();
      if (existingSubscription) {
        setSubscription(existingSubscription);
        setIsSubscribed(true);
        console.log("✅ Déjà abonné aux notifications");
        return true;
      }

      // Créer un nouvel abonnement
      const newSubscription = await reg.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(vapidPublicKey),
      });

      console.log("✅ Nouvelle subscription:", newSubscription);

      // Envoyer au backend
      const response = await fetch(`${process.env.REACT_APP_BACKEND_URL}/api/save-subscription`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ subscription: newSubscription }),
      });

      if (response.ok) {
        setSubscription(newSubscription);
        setIsSubscribed(true);
        console.log("Abonnement enregistré avec succès !");
        return true;
      } else {
        console.error("Erreur lors de l'enregistrement de l'abonnement");
        return false;
      }
    } catch (err) {
      console.error("Erreur abonnement:", err);
      return false;
    }
  };

  // Se désabonner des notifications push
  const unsubscribeUser = async () => {
    if (!subscription) return false;

    try {
      const reg = await navigator.serviceWorker.ready;
      const result = await subscription.unsubscribe();

      if (result) {
        setSubscription(null);
        setIsSubscribed(false);
        console.log("Désabonnement réussi");
        return true;
      }
    } catch (error) {
      console.error("Erreur lors du désabonnement:", error);
    }

    return false;
  };

  return {
    isSupported,
    isSubscribed,
    subscription,
    vapidPublicKey,
    hasAskedPermission,
    subscribeUser,
    unsubscribeUser
  };
};
